const handles = document.querySelectorAll('.drag-handle');
const data = Array.from(handles).map(h => {
  const row = h.closest('.group');
  if(!row) return null;
  const inputs = row.querySelectorAll('input');
  const code = inputs[0]?.value || '';
  const name = inputs[1]?.value || '';
  return { code, name };
}).filter(Boolean);
automaSetVariable('scraped_codebook_properties', data);
automaNextBlock({ properties: data });
